# PROGRESS INDICATOR
# ──────────────────────────────────────────────────────────
def render_progress(current_stage):
    n = len(STAGES)
    # fill width: from first to current circle
    fill_pct = ((current_stage - 1) / (n - 1)) * 100 if n > 1 else 0

    circles_html = ""
    for i, label in enumerate(STAGES):
        s = i + 1
        if s < current_stage:
            c_cls, l_cls, icon = "done",   "done",   "✓"
        elif s == current_stage:
            c_cls, l_cls, icon = "active", "active", str(s)
        else:
            c_cls, l_cls, icon = "future", "future", str(s)

        short = label.replace(" & ", " &<br>").replace("ESG ", "ESG<br>")
        circles_html += f"""
        <div class="progress-step">
          <div class="step-circle {c_cls}">{icon}</div>
          <div class="step-label {l_cls}">{short}</div>
        </div>"""

    st.markdown(f"""
    <div class="progress-wrap">
      <div class="progress-track">
        <div class="progress-line-bg"></div>
        <div class="progress-line-fill" style="width:calc({fill_pct}% * (100% - 28px) / 100% + 0px);
             width: calc({fill_pct / 100:.4f} * (100% - 28px));"></div>
        {circles_html}
      </div>
    </div>
    """, unsafe_allow_html=True)


